# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 500;

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
    }

    public void GainCurrency(int amount)
    {
        currency += amount;
    }

    public bool CanMakePurchase(int price)
    {
        return currency >= price;
    }

    public void MakePurchase(int price)
    {
        if (CanMakePurchase(price))
        {
            currency -= price;
        }
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;
    private int itemPrice = 100;

    public void PurchaseItem()
    {
        if (playerStats.CanMakePurchase(itemPrice))
        {
            playerStats.MakePurchase(itemPrice);
            Debug.Log("Purchase successful!");
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;

    void Start()
    {
        playerStats = new PlayerStats();
        Shop shop = new Shop { playerStats = playerStats };

        playerStats.TakeDamage(20);
        Debug.Log("Player Health: " + playerStats.health);

        playerStats.GainCurrency(150);
        Debug.Log("Player Currency: " + playerStats.currency);

        shop.PurchaseItem();
        Debug.Log("Player Currency: " + playerStats.currency);
    }
}